  /**
   * Tính hoa hồng cho booking - chỉ áp dụng commission có giá trị cao nhất
   * @param baseTotal - Tổng giá phòng
   * @param surchargeTotal - Tổng phụ phí
   * @param stayNights - Số đêm lưu trú
   * @param guestCount - Số khách
   * @param commissions - Danh sách cấu hình hoa hồng (đã active)
   * @returns Hoa hồng cao nhất
   */
  private calcCommission(
    baseTotal: number,
    surchargeTotal: number,
    stayNights: number,
    guestCount: number,
    commissions: CommissionSetting[],
  ): number {
    if (!this.isValidCommissionParams(baseTotal, stayNights) || commissions.length === 0) {
      return 0;
    }

    return Math.max(
      0,
      ...commissions.map(commission => {
        const baseAmount = this.getCommissionBaseAmount(commission.serviceType, baseTotal, surchargeTotal);
        return baseAmount > 0 ? this.calculateCommissionAmount(baseAmount, stayNights, guestCount, commission) : 0;
      }),
    );
  }

  private isValidCommissionParams(baseTotal: number, stayNights: number): boolean {
    if (baseTotal <= 0 || stayNights <= 0) {
      this.logger.warn('Invalid parameters for commission calculation', { baseTotal, stayNights });
      return false;
    }
    return true;
  }

  private getCommissionBaseAmount(serviceType: ServiceType, baseTotal: number, surchargeTotal: number): number {
    const baseAmountMap: Record<ServiceType, number> = {
      [ServiceType.ROOM_PRICE]: baseTotal,
      [ServiceType.SURCHARGE_FEE]: surchargeTotal,
    };
    return baseAmountMap[serviceType] ?? 0;
  }

  /**
   * Tính giá trị hoa hồng dựa trên calculationType
   */
  private calculateCommissionAmount(
    baseAmount: number,
    stayNights: number,
    guestCount: number,
    commission: CommissionSetting,
  ): number {
    const amount = Number(commission.commissionAmount);
    const isPercentage = commission.commissionUnit === UnitType.PERCENTAGE;

    const calculators: Record<FeeCalculationType, () => number> = {
      [FeeCalculationType.PER_ROOM_NIGHT]: () => (isPercentage ? (baseAmount * amount) / 100 : amount * stayNights),
      [FeeCalculationType.PER_BOOKING]: () => (isPercentage ? (baseAmount * amount) / 100 : amount),
      [FeeCalculationType.PER_SERVICE]: () => (isPercentage ? (baseAmount * amount) / 100 : amount * guestCount),
    };

    const calculator = calculators[commission.calculationType];
    if (!calculator) {
      this.logger.warn('Unknown commission calculation type', { calculationType: commission.calculationType });
      return 0;
    }

    return calculator();
  }

